<?php namespace App\Repositories\FrontOffice;use App\Repositories\BaseRepository;use App\Models\FrontOffice\Visitor;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class VisitorRepository extends BaseRepository{    public function __construct(Visitor $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByPurpose(string $purpose): Collection    {        return $this->findByField('purpose', $purpose);    }    public function findByStatus(string $status): Collection    {        return $this->findByField('status', $status);    }    public function getByDate(string $date): Collection    {        return $this->query()->whereDate('visit_date', $date)->get();    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('visit_date', [$startDate, $endDate])->get();    }    public function searchVisitors(string $keyword): Collection    {        return $this->query()->where('name', 'like', "%{$keyword}%")->orWhere('phone', 'like', "%{$keyword}%")->orWhere('email', 'like', "%{$keyword}%")->orWhere('company', 'like', "%{$keyword}%")->get();    }    public function getTodayVisitors(): Collection    {        return $this->query()->whereDate('visit_date', now())->get();    }    public function markCheckout(int $id): bool    {        return $this->update($id, ['check_out' => now(), 'status' => 'departed']);    }    public function getByWhomToMeet(string $person): Collection    {        return $this->findByField('whom_to_meet', $person);    }    public function getByVisitedEmployee(int $employeeId): Collection    {        return $this->findByField('employee_id', $employeeId);    }}